select v_1 as "r_name", v_2 as "r_order", v_3 as "n_name", v_4 as "neighbour1", v_5 as "neighbour2", v_6 as "tile" from (select * from (select * from (select *, row_number() over (partition by v_7 order by v_3) as v_2, ntile(2) over (partition by v_7 order by v_3) as v_6, lag(v_3, 1, NULL) over (partition by v_7 order by v_3) as v_4, lead(cast(v_3 as text), 2, '-') over (partition by v_7 order by v_3) as v_5 from (select "n_nationkey" as v_8, "n_name" as v_3, "n_regionkey" as v_7, "n_comment" as v_9 from "nation") s) s) l inner join (select "r_regionkey" as v_10, "r_name" as v_1, "r_comment" as v_11 from "region") r on v_7 = v_10) s
